const VIEW_BOX = "91 195 93 97"

export default function DiningTableOverlay({ isHovered, onClick, onMouseEnter, onMouseLeave }) {
  return (
    <svg
      viewBox={VIEW_BOX}
      xmlns="http://www.w3.org/2000/svg"
      style={{ cursor: 'pointer', display: 'block', width: '100%', height: '100%', overflow: 'visible' }}
      onClick={onClick}
      onMouseEnter={onMouseEnter}
      onMouseLeave={onMouseLeave}
    >
      <defs>
        <clipPath id="dt-clip">
          {PATHS.map((d, i) => <path key={i} d={d} />)}
        </clipPath>
      </defs>

      <rect x="91" y="195" width="93" height="97" fill="transparent" clipPath="url(#dt-clip)" />

      {isHovered && (
        <rect x="91" y="195" width="93" height="97"
          fill="rgba(255,255,255,0.35)" clipPath="url(#dt-clip)" />
      )}
    </svg>
  )
}
